# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import json
from typing import Dict
from websockets import connect, serve

class Player:
    def __init__(self, id: int):
        self.id = id
        self.inventory = {}

    async def send(self, message: dict):
        await self.websocket.send(json.dumps(message))

class GameServer:
    def __init__(self):
        self.players: Dict[int, Player] = {}

    async def on_connected(self, websocket, path):
        player = Player(len(self.players) + 1)
        self.players[player.id] = player
        player.websocket = websocket
        await player.send({"type": "connect", "id": player.id})
        print(f"Player {player.id} connected.")

    async def on_message(self, websocket, message: str):
        data = json.loads(message)
        sender_id = data["sender"]
        if sender_id not in self.players:
            return
        player = self.players[sender_id]
        action = data["action"]
        if action == "trade":
            target_id = data["target"]
            item_name = data["item"]
            if target_id not in self.players:
                await player.send({"type": "error", "message": f"Player {target_id} does not exist."})
                return
            target_player = self.players[target_id]
            if item_name not in player.inventory:
                await player.send({"type": "error", "message": f"You don't have the item {item_name}."})
                return
            if item_name in target_player.inventory:
                await player.send({"type": "error", "message": f"Target player already has the item {item_name}."})
                return
            player.inventory[item_name] -= 1
            target_player.inventory[item_name] = 1
            await player.send({"type": "trade_success", "item": item_name})
            await target_player.send({"type": "trade_success", "item": item_name})
        elif action == "list_inventory":
            items = list(player.inventory.keys())
            if not items:
                items = ["none"]
            await player.send({"type": "list_inventory", "items": items})
        else:
            print(f"Unknown action {action} from player {sender_id}")

async def main():
    server = GameServer()
    start_server = serve(server.on_connected, "localhost", 8765)
    await asyncio.gather(*[start_server])
    asyncio.get_event_loop().run_forever()

if __name__ == "__main__":
    asyncio.run(main())